import fs from 'node:fs/promises';
import path from 'node:path';
import crypto from 'node:crypto';
const out = path.join(process.cwd(), 'artifacts/proofzero-planning-lab');
await fs.mkdir(out, {recursive:true});
const scenario = process.env.SCENARIO || 'research';
const write = async (name,obj) => fs.writeFile(path.join(out,name), JSON.stringify(obj,null,2),'utf8');
const hash = obj => crypto.createHash('sha256').update(JSON.stringify(obj)).digest('hex');
const manifest = {schema:'goalos.proofzero_planning.artifact_manifest.v1', scenario, generatedAt:new Date().toISOString(), publicSafe:true, valueMoved:0};
const evidenceState = {claimsCoverage:.74, contradictionLoad:.22, validatorCapacity:.88, proofDebt:33, risk:'bounded'};
const search = {actions:['delegate','retrieve','code','test','validate','escalate','stop','quarantine'], selected:'validate_then_reanalyze', constraints:['budget','tool scope','risk class','validator availability','escalation rule']};
const reanalyze = {accepted:['old-run-001'], quarantined:['old-run-002'], rule:'Only replayable provenance-preserving traces can update routing.'};
const certificate = {decision:'REVIEW_READY', planner:'B3 ProofZero work planner', gates:{proof:true,replay:true,validator:true,risk:true,rollback:true,humanAuthorityPreserved:true}, valueMoved:0};
await write('00_manifest.json', manifest);
await write('01_evidence_state.json', evidenceState);
await write('02_bounded_search.json', search);
await write('03_evidence_reanalyze_ledger.json', reanalyze);
await write('04_router_policy_update.json', {update:'prefer validator-aware search under high proof debt', bundleHash:hash({manifest,evidenceState,search,reanalyze})});
await write('05_proofzero_planning_certificate.json', certificate);
await fs.writeFile(path.join(out,'README.md'), `# GoalOS ProofZero Planning Lab\n\nScenario: ${scenario}\n\nThis synthetic public-safe bundle demonstrates bounded work search over proof-relevant evidence states. No user data, no uploads, no wallets, no payments, no value moved.\n`, 'utf8');
console.log(`GoalOS ProofZero Planning Lab bundle generated at ${out}`);
